sealed class CatalogOpenException: kotlin.Exception() {
    
    class ParseFailed(
        ) : CatalogOpenException() {
        override val message
            get() = ""
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<CatalogOpenException> {
        override fun lift(error_buf: RustBuffer.ByValue): CatalogOpenException = FfiConverterTypeCatalogOpenError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeCatalogOpenError : FfiConverterRustBuffer<CatalogOpenException> {
    override fun read(buf: ByteBuffer): CatalogOpenException {
        

        return when(buf.getInt()) {
            1 -> CatalogOpenException.ParseFailed()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: CatalogOpenException): ULong {
        return when(value) {
            is CatalogOpenException.ParseFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: CatalogOpenException, buf: ByteBuffer) {
        when(value) {
            is CatalogOpenException.ParseFailed -> {
                buf.putInt(1)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




